SELECT country_id
FROM healthy_life_expectancy
WHERE healthy_life_expectancy = (
  SELECT MAX(healthy_life_expectancy)
  FROM healthy_life_expectancy
);

SELECT social_support, year
FROM social_support
WHERE country_id = 0;

SELECT DISTINCT country_id
FROM social_support
WHERE year = 2023;

SELECT AVG(healthy_life_expectancy) AS average_healthy_life_expectancy
FROM healthy_life_expectancy
WHERE year = 2023;

SELECT AVG(social_support) AS average_social_support, year
FROM social_support
GROUP BY year;

SELECT AVG(gdp_per_capita) AS average_gdp_per_capita
FROM gdp_per_capita
WHERE year = (SELECT MAX(year) FROM gdp_per_capita);
